import React, { useEffect, useRef, useState } from 'react';
import './App.css';

const SAMPLE_RESPONSE = "Sure! Here's a short streaming reply. It arrives token by token so the UI feels responsive.";

function startFakeStream(text, onChunk, onDone) {
  const tokens = text.split(' ');
  let i = 0;
  const id = window.setInterval(() => {
    const chunk = tokens[i] + (i < tokens.length - 1 ? ' ' : '');
    onChunk(chunk);
    i += 1;
    if (i >= tokens.length) {
      window.clearInterval(id);
      onDone();
    }
  }, 120);
  return () => window.clearInterval(id);
}

